import { cacheTag } from "next/cache";

import { getAllProducts, syncLatestCatalog } from "./db";

export async function getCachedCatalog() {
  "use cache";

  cacheTag("products");

  return getAllProducts();
}

export async function runCatalogSync() {
  await syncLatestCatalog();
}

let syncRun = 0;
let products = [
  {
    id: 1,
    name: "Laptop",
    sku: "LAP-100",
    price: 999,
    inventory: 42,
    availability: "In stock",
  },
  {
    id: 2,
    name: "Phone",
    sku: "PHN-210",
    price: 699,
    inventory: 18,
    availability: "In stock",
  },
  {
    id: 3,
    name: "Tablet",
    sku: "TAB-330",
    price: 499,
    inventory: 0,
    availability: "Backorder",
  },
  {
    id: 4,
    name: "Headphones",
    sku: "HDP-440",
    price: 199,
    inventory: 76,
    availability: "In stock",
  },
  {
    id: 5,
    name: "Watch",
    sku: "WCH-550",
    price: 299,
    inventory: 9,
    availability: "Low stock",
  },
];

let lastSyncedAt = "2026-07-17T09:00:00.000Z";

export async function getAllProducts() {
  await new Promise((resolve) => setTimeout(resolve, 100));

  return {
    items: products.map((product) => ({ ...product })),
    lastSyncedAt,
    syncRun,
  };
}

export async function syncLatestCatalog() {
  await new Promise((resolve) => setTimeout(resolve, 1500));

  syncRun += 1;
  const inventoryOffset = syncRun % 4;

  products = products.map((product, index) => {
    const priceDelta = ((syncRun + index) % 3) * 5;
    const nextInventory = Math.max(
      0,
      product.inventory + inventoryOffset * 3 - (index % 3) * 4,
    );

    let availability = "In stock";
    if (nextInventory === 0) {
      availability = "Out of stock";
    } else if (nextInventory < 12) {
      availability = "Low stock";
    }

    return {
      ...product,
      price: product.price + priceDelta,
      inventory: nextInventory,
      availability,
    };
  });

  lastSyncedAt = new Date().toISOString();
}

